#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv_dw2d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    TORCH_CHECK(x.dim() == 4, "x must be 4D NCHW");
    TORCH_CHECK(weight.dim() == 4, "weight must be 4D [C,1,K,K]");
    TORCH_CHECK(x.scalar_type() == at::kFloat && weight.scalar_type() == at::kFloat,
                "dtype must be float32");

    const auto N = x.size(0);
    const auto C = x.size(1);
    const auto H = x.size(2);
    const auto W = x.size(3);
    const auto K = weight.size(2);

    TORCH_CHECK(weight.size(0) == C && weight.size(1) == 1 && weight.size(3) == K,
                "weight shape mismatch for depthwise");

    const auto Ho = H - K + 1;
    const auto Wo = W - K + 1;
    TORCH_CHECK(Ho >= 0 && Wo >= 0, "invalid output size");

    at::Tensor result = at::empty({N, C, Ho, Wo}, x.options());
    EXEC_NPU_CMD(aclnnConvDepthwise2dSquareInputSquareKernelCustom, x, weight, result);
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_depthwise_2d_square_input_square_kernel_custom", &conv_dw2d_impl_npu);
}

